#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 1e6+5;
const LL MOD = 1e9+7;
LL T,n,m,Ans;
LL p[N],cnt,mu[N];
LL f[N],g[N],F[N],G[N];
bool vis[N];
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
LL QP(LL x,LL y){
    LL as=1;x%=MOD,y%=MOD-1;
    while(y){
        if(y&1)as=as*x%MOD;
        x=x*x%MOD,y>>=1;
    }return as;
}
LL inv(LL x){return QP(x,MOD-2);}
void init(LL up){
    f[1]=1,g[1]=1,mu[1]=1;
    vis[0]=1,vis[1]=1,cnt=0;
    for(LL i=2;i<=up;i++){
        f[i]=(f[i-1]+f[i-2])%MOD;
        g[i]=inv(f[i]);
        if(!vis[i])p[++cnt]=i,mu[i]=-1;
        for(int j=1;j<=cnt&&i*p[j]<=up;j++){
            vis[i*p[j]]=1;
            if(i%p[j]==0){mu[i*p[j]]=0;continue;}
            else mu[i*p[j]]=mu[i]*mu[p[j]];
        }
    }for(LL i=1;i<=up;i++)F[i]=1;
    for(LL i=1;i<=up;i++){
        if(!mu[i])continue;
        for(LL j=i;j<=up;j+=i){
            LL mul=f[j/i];
            if(mu[i]<0)mul=g[j/i];
            F[j]=F[j]*mul%MOD;
        }
    }F[0]=1,G[0]=1;
    for(LL i=1;i<=up;i++)
        F[i]=F[i-1]*F[i]%MOD,G[i]=inv(F[i]);
    return;
}
int main(){
    T=read();init(1000000);
    while(T--){
        n=read(),m=read();
        if(n>m)swap(n,m);Ans=1;
        for(LL i=1,j;i<=n;i=j+1){
            j=min(n/(n/i),m/(m/i));
            LL bas=F[j]*G[i-1];
            LL res=QP(bas,(n/i)*(m/i));
            Ans=Ans*res%MOD;
        }cout<<Ans<<"\n";
    }
    return 0;
}
